import{_ as a,o as t,c as s,a3 as o}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"18. Part Time Employment","description":"","frontmatter":{"title":"18. Part Time Employment","eba":"Nurses and Midwives 2024-2028","topics":["leave","hours","overtime","shift-work"]},"headers":[],"relativePath":"ebas/nurses-midwives/employment-types/18-part-time-employment.md","filePath":"ebas/nurses-midwives/employment-types/18-part-time-employment.md"}'),r={name:"ebas/nurses-midwives/employment-types/18-part-time-employment.md"};function m(i,e,n,l,p,h){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="_18-part-time-employment" tabindex="-1">18. Part Time Employment <a class="header-anchor" href="#_18-part-time-employment" aria-label="Permalink to &quot;18. Part Time Employment&quot;">​</a></h1><p><strong>18.1</strong> A part-time Employee is one who is engaged to work less than an average of 38 hours per week.</p><p><strong>18.2</strong> The number of hours worked by a part-time Employee may vary from week to week by mutual agreement.</p><p><strong>18.3</strong> A part-time Employee will be paid an hourly rate equal to 1/38th of the weekly salary for the Employee&#39;s classification. Payments for shift work (<a href="/eba/ebas/nurses-midwives/allowances/34-shift-allowance.html">clause 34</a>), Saturdays and Sundays (<a href="/eba/ebas/nurses-midwives/hours-of-work/48-special-rates-for-saturdays-and-sundays.html">clause 48</a>), Overtime (<a href="/eba/ebas/nurses-midwives/hours-of-work/49-overtime.html">clause 49</a>) and Public Holidays (<a href="/eba/ebas/medical-specialists/leave/56-public-holidays.html">clause 56</a>) also apply to part-time Employees.</p><p><strong>18.4</strong> Where a part-time Employee has an entitlement to leave under this Agreement, the part- time Employee will be paid according to the number of hours the Employee would have worked on the day/s on which the leave was taken except as provided at clause 0 (Cashing Out of Annual Leave).</p><p>Plain language terms: part time, fractional.</p>',6)])])}const y=a(r,[["render",m]]);export{u as __pageData,y as default};
